import{_ as n,Z as e,P as r,g as s,k as l,m as t}from"./chunks/framework.Dp5g00Bf.js";const u=JSON.parse('{"title":"标签打印调试心得","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/1-前端/标签打印调试心得/index.md","filePath":"views/1-开发🌏/1-前端/标签打印调试心得/index.md","lastUpdated":1778336291000}'),d={name:"views/1-开发🌏/1-前端/标签打印调试心得/index.md"};function p(h,a,c,m,g,_){const o=e("NolebaseGitContributors"),i=e("NolebaseGitChangelog");return r(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[a[0]||(a[0]=l('<h1 id="标签打印调试心得" tabindex="-1">标签打印调试心得 <a class="header-anchor" href="#标签打印调试心得" aria-label="Permalink to &quot;标签打印调试心得&quot;">​</a></h1><p>如果是制造业的前端，你需要做的打印页面其实频率最高的是标签纸的打印。而标签纸是一种非标纸张，它不同于A4等标准纸张大小易于调试。我们在调试的过程中往往会遇到格式问题，或者文字溢出，表格高度自动增高等等问题。这篇文档会介绍如何解决这些常见的标签打印问题。</p><h2 id="解决表格高度不固定" tabindex="-1">解决表格高度不固定 <a class="header-anchor" href="#解决表格高度不固定" aria-label="Permalink to &quot;解决表格高度不固定&quot;">​</a></h2><p>标签的打印往往伴随着表格的内容。这时候我们在调试过程中会发现，字段长度不一样的两张表格的高度会出现差异，如果高度超出纸张高度会导致打印出两张。解决思路就是给表格设置固定的高度和宽度。超出后使用 <code>overflow:hidden</code>，这样的好处是如果文字没有撑满表格高度，表格自己会撑满。如果撑满并溢出了，不会让打印机吐多余的纸张。</p><p>但是这么做也有个弊端那就是，当内容过长的时候，底部内容会显示不全。<strong>这里的解决思路就是对于内容可能会过长需要换行显示的表格行**</strong>(td标签)指定一个固定的高度**。这样的好处就是这一行的文字多行显示与单行显示所占用的高度是一样的。不会因为一个标签字段内容占用一行，另外一个标签字段占用两行导致的高低不一致的问题。</p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260508092831412.avif" alt=""></p><p>那么如果内容过多，高度还是溢出导致无法显示完整该怎么办呢？</p><p>以下提供这么几种方法：</p><ul><li><strong>表格td标签默认的padding边距设置为0</strong></li><li><strong>如果有二维码这些高度可以缩短的请进行缩短</strong></li><li><strong>将部分单元格合并成一个，在同一个单元格内并排显示</strong></li><li><strong>使用zoom对table或者内部元素进行缩放(终极杀手锏，谁用谁知道)</strong></li></ul><p>解决后的样式：</p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260508093040138.avif" alt=""></p><h2 id="解决二维码垂直居中显示问题" tabindex="-1">解决二维码垂直居中显示问题 <a class="header-anchor" href="#解决二维码垂直居中显示问题" aria-label="Permalink to &quot;解决二维码垂直居中显示问题&quot;">​</a></h2><p>标签里往往我们需要加入二维码，并且这个二维码可以垂直居中显示，实现方式参照<a href="./../table表格里垂直居中元素/">table表格里垂直居中元素</a></p><h2 id="解决浏览器默认边距问题" tabindex="-1">解决浏览器默认边距问题 <a class="header-anchor" href="#解决浏览器默认边距问题" aria-label="Permalink to &quot;解决浏览器默认边距问题&quot;">​</a></h2><p>参照教程<a href="./../printjs使用指南/">printjs使用指南</a></p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>解决打印格式问题的核心思想就是，大部分纸张大小是固定死的，我们不能用web开发的思维去理解纸张上面的布局，web空间是无限的因为我们有滚动条，但是纸张是没有滚动条的，他在物理层面就是多大面积就显示多少的内容。所以我们主要是解决如何在有限的纸张面积里显示不同字数的内容，因此我们可以从此处下手，用上述的各种手段去解决问题。</p>',17)),t(o),t(i)])}const f=n(d,[["render",p]]);export{u as __pageData,f as default};
